const it = $input.first().json;
const exec = it.execution || {};
const wf = it.workflow || {};
const err = exec.error || {};
const rawStack = (err.stack || err.message || 'unknown error').toString();
const errorMessage = rawStack.length > 1800 ? rawStack.slice(0, 1800) + '...<truncated>' : rawStack;
const failingNode = err.node && err.node.name ? err.node.name : null;
const findPipelineRunId = () => {
  const data = exec.data && exec.data.resultData && exec.data.resultData.runData;
  if (data && typeof data === 'object') {
    for (const nodeName of Object.keys(data)) {
      const runs = data[nodeName];
      if (!Array.isArray(runs)) continue;
      for (const r of runs) {
        const items = r && r.data && r.data.main && r.data.main[0];
        if (!Array.isArray(items)) continue;
        for (const item of items) {
          const j = item && item.json;
          if (j && j.pipeline_run_id) return j.pipeline_run_id;
          if (j && j.body && j.body.pipeline_run_id) return j.body.pipeline_run_id;
        }
      }
    }
  }
  return null;
};
const pipelineRunId = findPipelineRunId();
const workflowName = wf.name || 'unknown';
const isOnboard = /onboard/i.test(workflowName);
return [{ json: {
  pipeline_run_id: pipelineRunId,
  workflow_id: wf.id || null,
  workflow_name: workflowName,
  execution_id: exec.id || null,
  execution_url: exec.url || null,
  failing_node: failingNode,
  error_message: errorMessage,
  error_class: (err.name || 'Error').toString(),
  is_onboard: isOnboard,
  failed_at: new Date().toISOString(),
  can_patch_run: pipelineRunId !== null
} }];
